INSERT INTO da_email_templates
  (template_key, name, subject, preheader, blocks, is_marketing, sort_order, delay_label)
VALUES
  ('post_course_welcome', 'Daisy First Aid Customers (post-class thank you)', 'Thank you from Daisy First Aid', 'Additional information following your class today', '[{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Email_header_-_thank_you_email.jpg","alt":"Congratulations on completing your Daisy First Aid class!","href":"https://www.daisyfirstaid.com/"},{"type":"heading","text":"Thank You"},{"type":"paragraph","text":"**We hope you enjoyed your class.**"},{"type":"paragraph","text":"Hopefully, you are now feeling more confident with your new skills and ready for action if need be."},{"type":"paragraph","text":"Below are a number of links to useful information linked to our class, including a recap on how to place someone into the recovery position, further information on the differences between gagging and choking and 5 things we recommend that everyone should have at home (aside from our First Aid Kit of course!)."},{"type":"paragraph","text":"Following this email, we''ll send you a monthly topic refresher email and your local trainer may also be in touch (if relevant) to answer any specific questions from your class."},{"type":"divider"},{"type":"heading","text":"Useful links & information for you..."},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Untitled_design_48-2.png","alt":"Recovery Position video","href":"https://www.daisyfirstaid.com/how-to-put-someone-into-the-recovery-postion/","width":300},{"type":"paragraph","text":"**Recovery Position — Video Recap**"},{"type":"paragraph","text":"Watch our recap video showing how to place a child into the recovery position"},{"type":"button","label":"Watch Now","url":"https://www.daisyfirstaid.com/how-to-put-someone-into-the-recovery-postion/"},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Untitled_design_51.png","alt":"5 items to have at home","href":"https://www.daisyfirstaid.com/top-5-items-to-have-at-home/","width":300},{"type":"paragraph","text":"**5 Items to Have at Home**"},{"type":"paragraph","text":"See the 5 items to have at home alongside your Daisy First Aid kit"},{"type":"button","label":"Read Now","url":"https://www.daisyfirstaid.com/top-5-items-to-have-at-home/"},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Untitled_design_50.png","alt":"Gagging vs choking","href":"https://www.daisyfirstaid.com/the-difference-between-gagging-choking/","width":300},{"type":"paragraph","text":"**Gagging Vs Choking Differences**"},{"type":"paragraph","text":"Understand the differences between gagging & choking to help with weaning"},{"type":"button","label":"Watch Now","url":"https://www.daisyfirstaid.com/the-difference-between-gagging-choking/"},{"type":"divider"},{"type":"paragraph","text":"**Links to relevant charities & resources we may have mentioned in class:**"},{"type":"list","items":["[The UK Sepsis Trust](https://sepsistrust.org/about/about-sepsis/)","[Meningitis Now](https://www.meningitisnow.org/meningitis-explained/signs-and-symptoms/)","[The Allergy Team](https://theallergyteam.com/families/)"]}]'::jsonb, true, 1, '7 hours after the class'),
  ('recap_anaphylaxis', 'Anaphylaxis Recap', 'How much do you remember about Anaphylaxis?', 'Take our quiz to find out how much you remember about severe allergies', '[{"type":"heading","text":"Anaphylaxis — how much do you remember?"},{"type":"paragraph","text":"It''s been about 4 weeks since your Daisy First Aid class and we wanted to check in and give you a quick recap on anaphylaxis."},{"type":"paragraph","text":"**Things to remember:**"},{"type":"list","items":["It''s a severe allergic reaction with swelling of the airways","It''s usually an immediate reaction and it is life threatening","You must call 999 immediately if you suspect someone is having an anaphylactic reaction","Lay the person down and raise their legs and administer their auto-adrenaline injector if they have one","Keep the person talking and monitor their breathing","If they stop breathing, begin CPR immediately"]},{"type":"button","label":"Take Our Anaphylaxis Quiz","url":"https://www.surveymonkey.co.uk/r/YS3SCKJ"},{"type":"divider"},{"type":"heading","text":"Useful links & information for you..."},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Untitled_design_57.png","alt":"The Allergy Team","href":"https://theallergyteam.com/","width":170},{"type":"paragraph","text":"**We''ve teamed up with The Allergy Team**"},{"type":"paragraph","text":"The Allergy Team have some excellent resources for parents, schools & businesses on their website to help improve understanding and inclusion around allergies."},{"type":"button","label":"Visit The Allergy Team Website","url":"https://theallergyteam.com/"}]'::jsonb, true, 2, '+28 days'),
  ('recap_choking', 'Choking Recap', 'Reminder: How to save someone from choking', 'Reminder on how to save your baby or child from choking', '[{"type":"heading","text":"Choking"},{"type":"paragraph","text":"**Reminder: what to do if someone chokes**"},{"type":"paragraph","text":"Choking is always a scary thing to happen, but as we discussed in class, remember that choking is silent and we need to act quickly."},{"type":"paragraph","text":"If a **baby** is choking call for help and repeat a cycle of:"},{"type":"list","items":["5 x Back Blows","5 x Chest Thrusts"]},{"type":"paragraph","text":"If a **child** or **adult** is choking then repeat a cycle of:"},{"type":"list","items":["5 x Back Blows","5 x Abdominal Thrusts"]},{"type":"paragraph","text":"Keep repeating the relevant cycle until either..."},{"type":"list","items":["The item comes out","Help arrives","They lose consciousness - in which case, start CPR"]},{"type":"divider"},{"type":"paragraph","text":"**Things to remember:**"},{"type":"paragraph","text":"Call the ambulance asap - you can cancel it if you don''t need it."},{"type":"paragraph","text":"If you are on your own, do a round of back blows first, then call for help."},{"type":"paragraph","text":"**They must be checked at hospital if...**"},{"type":"list","items":["They have chest or abdominal thrusts","Have a persistent cough afterwards","Have any difficulty swallowing afterwards"]}]'::jsonb, true, 3, '+42 days'),
  ('recap_head_injuries', 'Recap: Head Injuries', 'Can you remember how to monitor a head injury?', 'You should monitor a head injury for 24 hours - can you remember how?', '[{"type":"heading","text":"Head Injuries"},{"type":"paragraph","text":"**Can you remember how to monitor a head injury?**"},{"type":"paragraph","text":"Here is a quick reminder on how to monitor head injuries..."},{"type":"paragraph","text":"You must monitor the child regularly for 24 hours following a head injury - even if they seem absolutely fine."},{"type":"paragraph","text":"**The 3 things you need to check are:**"},{"type":"list","items":["Their skin colour is as you expect to find it - no paleness/blotching","They are responsive - if they are asleep, you don''t need to wake them, just check if you can get them to move of their own accord","That they are breathing normally"]},{"type":"paragraph","text":"Remember that all head injuries should be checked with a medical professional and that some serious symptoms can be delayed. If in doubt, get them checked out!"},{"type":"divider"},{"type":"heading","text":"Useful links & information for you..."},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/DFA_Manual.jpeg","alt":"Paediatric First Aid Made Easy manual","width":380},{"type":"paragraph","text":"**Did you know..?**"},{"type":"paragraph","text":"The number 1 cause of head injuries is from a fall."},{"type":"paragraph","text":"In the UK around 200,000 people per year are admitted to hospital following a head injury."}]'::jsonb, true, 4, '+42 days'),
  ('recap_cpr', 'Recap: CPR', 'CPR is easy as ABC', 'Reminder on how to perform CPR to save your loved one''s life', '[{"type":"heading","text":"Cardiopulmonary Resuscitation"},{"type":"paragraph","text":"**CPR - Easy as ABC**"},{"type":"paragraph","text":"It''s been a few months since you did your Daisy First Aid class..."},{"type":"paragraph","text":"Hopefully, you won''t need some of the skills you learned, but it''s always good to have a reminder!"},{"type":"paragraph","text":"Think back to the class where you would have..."},{"type":"list","items":["Opened the **AIRWAY** by lifting the chin","Done a 10 second **BREATHING** check","If not breathing normally... started **CPR**"]},{"type":"paragraph","text":"The CPR sequence for a **baby/child** (newborn up to the age of 18 years old):"},{"type":"list","items":["5 rescue breaths","15 chest compressions","2 breaths"]},{"type":"paragraph","text":"Continue to repeat the cycle of 15:2 until help arrives."},{"type":"paragraph","text":"If you are faced with an **adult** (over the age of 18 years old) then do as above but skip the 5 initial rescue breaths. Start straight away with 15 chest compressions."},{"type":"paragraph","text":"Remember - always call for help asap!"},{"type":"divider"},{"type":"heading","text":"Useful links & information for you..."},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/app_instagram_logo_media_popular_social.png","alt":"Instagram","href":"https://www.instagram.com/daisyfirstaid","width":90},{"type":"paragraph","text":"**Are you on Instagram?**"},{"type":"paragraph","text":"We share lots of useful first aid advice for free via our Instagram account!"},{"type":"paragraph","text":"Follow us on Instagram: [www.instagram.com/daisyfirstaid](https://www.instagram.com/daisyfirstaid)"}]'::jsonb, true, 5, '+42 days'),
  ('recap_febrile_convulsions', 'Febrile Convulsions', 'Can you remember the stages of a febrile convulsion?', 'Recap on how to deal with heat related seizures', '[{"type":"heading","text":"Febrile Convulsions"},{"type":"paragraph","text":"**Heat-related seizures**"},{"type":"paragraph","text":"If a baby or child''s temperature rises above 38 degrees, they can experience these convulsions as a result of core body temperature being so high."},{"type":"paragraph","text":"They aren''t dangerous, but they can be frightening - remember the 3 stages..."},{"type":"list","items":["1. Stiff and rigid body - back often arches","2. Jerky, uncontrolled movements - fitting and convulsing","3. Exhausted and limp"]},{"type":"paragraph","text":"You will need to time the seizure, protect them from any harm by placing something soft under their head and loosening anything restrictive. When the jerking movements stop, cool them down quickly but naturally and place in the recovery position."},{"type":"paragraph","text":"Call 999 if it is their first ever seizure, if it lasts 5 mins or more or if they have multiple seizures in a short space of time."},{"type":"paragraph","text":"Remember that your baby or child is safe and there are no lasting effects from the seizure happening, but you need to get them the right help as needed."},{"type":"divider"},{"type":"heading","text":"Useful links & information for you..."},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/facebook_social_media_social.png","alt":"Facebook","href":"https://www.facebook.com/daisyfirstaid","width":90},{"type":"paragraph","text":"**Are you on Facebook?**"},{"type":"paragraph","text":"We share lots of useful first aid advice and information via our Facebook page"},{"type":"paragraph","text":"Follow us on Facebook: [www.facebook.com/daisyfirstaid](https://www.facebook.com/daisyfirstaid)"}]'::jsonb, true, 6, '+42 days'),
  ('recap_burns', 'Burns', 'A reminder on how to treat burns', 'Reminder on how to deal with burns at home', '[{"type":"heading","text":"Treating a burn"},{"type":"paragraph","text":"**Burns come with a big risk of infection**"},{"type":"paragraph","text":"The quicker you cool down a burn, the better!"},{"type":"paragraph","text":"Cooling quickly means there is less risk of infection and the burn is less likely to scar."},{"type":"paragraph","text":"Remember that burns should be cooled under luke-warm/tepid cool running water whenever possible and no creams or ointments should be used on them."},{"type":"paragraph","text":"Here is a quick reminder about each different depth of burn..."},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Screenshot_2023-11-20_at_12.57.18.png","alt":"Superficial burn","width":280},{"type":"paragraph","text":"**Superficial Burn** - Cool for 20 mins, wrap with clingfilm & seek medical advice"},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Screenshot_2023-11-20_at_12.57.27.png","alt":"Partial thickness burn","width":280},{"type":"paragraph","text":"**Partial Thickness** - Cool for 20 minutes, dress with clingfilm & call 999 if needed"},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Screenshot_2023-11-20_at_12.57.41.png","alt":"Full thickness burn","width":280},{"type":"paragraph","text":"**Full Thickness** - Cool for minimum of 20 mins, dress with clingfilm & always call 999"}]'::jsonb, true, 7, '+42 days'),
  ('quiz_general', 'General Quiz', 'Test your first aid knowledge', 'Take our quiz to find out how much you remember from your class', '[{"type":"heading","text":"Test Your Memory"},{"type":"paragraph","text":"**HOW MUCH DO YOU REMEMBER?**"},{"type":"paragraph","text":"It''s been a while since your Daisy First Aid class and we wondered how much you remember..."},{"type":"paragraph","text":"What do you need to do to save a child from choking?"},{"type":"paragraph","text":"Do you remember the signs of anaphylaxis?"},{"type":"paragraph","text":"How many rescue breaths did you need to do...?"},{"type":"paragraph","text":"First aid knowledge is something that we hope that we don''t need to put into practice, but if you aren''t using the knowledge from your class regularly, then you''ll be surprised how much you forget."},{"type":"divider"},{"type":"heading","text":"Useful links & information for you..."},{"type":"image","src":"https://dmvajkreuwknjqxyxmlv.supabase.co/storage/v1/object/public/email-assets/Screenshot_2023-11-20_at_13.00.08.png","alt":"Find a class on daisyfirstaid.com","href":"https://www.daisyfirstaid.com/find-a-first-aid-course/","width":460},{"type":"paragraph","text":"**Book a Refresher**"},{"type":"paragraph","text":"If you''d like to book a refresher class, you can find your local trainer on our website, see their availability and book online."},{"type":"button","label":"Find Your Local Trainer","url":"https://www.daisyfirstaid.com/find-a-first-aid-course/"}]'::jsonb, true, 8, '+42 days'),
  ('refresher', 'Refresher', 'Time flies when you have a little one around', 'It''s time for you to update your first aid knowledge', '[{"type":"heading","text":"I just blinked...!"},{"type":"paragraph","text":"**How much has your little one changed since you did your Daisy First Aid Class?**"},{"type":"paragraph","text":"All those milestones they have hit and the amazing things they have learned since we last saw you is just incredible to think about!"},{"type":"paragraph","text":"But it''s not just the children that have changed - did you know that the first aid guidelines are reviewed annually?"},{"type":"paragraph","text":"This means there may have been some changes since you last did a class with us!"},{"type":"paragraph","text":"The Resuscitation Council (UK), who govern our first aid guidelines, recommend an annual refresher for first aid for this very reason and to keep you fresh and confident in your skills."},{"type":"paragraph","text":"If you''d like to book a refresher class with us, there are a few options for you to choose from:"},{"type":"list","items":["Book a home class for 4 or more people","Join a live class online via zoom","Book a place at one of our venue classes","Purchase an e-learning course"]},{"type":"paragraph","text":"Click the button below to view our current class availability and your refresher class"},{"type":"button","label":"Find Your Local Trainer & Book Now","url":"https://www.daisyfirstaid.com/find-a-first-aid-course/"}]'::jsonb, true, 9, '+42 days'),
  ('refresher_elearning_option', 'Elearning Refresher Option', 'Refresh Your Knowledge Online', 'Refresh your first aid skills online at your own pace', '[{"type":"heading","text":"Update Your Skills & Confidence"},{"type":"paragraph","text":"**Refresh your knowledge with our e-learning course at your own pace**"},{"type":"paragraph","text":"We wrote last week to remind you that it''s time for your annual first aid refresher."},{"type":"paragraph","text":"It''s so worth doing as a parent or carer so that your skills are up to date in case you need them!"},{"type":"paragraph","text":"If you''d rather not re-take the class in person, we have a fantastic e-learning course that you can do at your own pace using your smartphone/tablet or computer."},{"type":"paragraph","text":"Our e-learning course takes around 2 hours to complete and you can stop and start as you need to. You even get a certificate at the end!"},{"type":"button","label":"Find Your Local Trainer","url":"https://www.daisyfirstaid.com/find-a-first-aid-course/"}]'::jsonb, true, 10, '+7 days')
